  `IS_STREAMING_YN` char(1) DEFAULT NULL,
  PRIMARY KEY (`MEDIA_OUTLET_ID`),
  KEY `FK_REF_MEDIA_OUTLET_REF_NETWORK_1` (`NET_ID`),
